/**
 * VulnScan Lite вЂ” Main App Component
 * Handles tab navigation and global state management
 */

import React, { useState, useEffect } from 'react';
import ScanPage from './pages/ScanPage';
import ResultPage from './pages/ScanResult';

const API_BASE = 'http://127.0.0.1:8000';

function App() {
  const [result, setResult]     = useState(null);
  const [activeTab, setActiveTab] = useState('scanner');
  const [history, setHistory]   = useState([]);

  const tabs = ['Scanner', 'Report', 'History'];

  // Fetch scan history when history tab is opened
  useEffect(() => {
    if (activeTab === 'history') fetchHistory();
  }, [activeTab]);

  const fetchHistory = async () => {
    try {
      const res  = await fetch(`${API_BASE}/api/history`);
      const data = await res.json();
      setHistory(data);
    } catch (e) {
      console.error('History fetch failed:', e);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: '#0a0a0a' }}>

      {/* в”Ђв”Ђ Header в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */}
      <header style={{
        padding        : '16px 32px',
        borderBottom   : '1px solid #1a1a1a',
        display        : 'flex',
        alignItems     : 'center',
        justifyContent : 'space-between',
      }}>
        {/* Logo */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <div style={{
            width          : '28px',
            height         : '28px',
            background     : '#00ff88',
            borderRadius   : '6px',
            display        : 'flex',
            alignItems     : 'center',
            justifyContent : 'center',
            fontSize       : '14px',
            fontWeight     : 'bold',
            color          : '#000',
          }}>V</div>
          <span style={{ fontWeight: '600', fontSize: '16px', color: '#fff' }}>
            VulnScan Lite
          </span>
        </div>

        {/* Disclaimer badge */}
        <span style={{
          background   : '#1a1200',
          color        : '#ffaa00',
          border       : '1px solid #332200',
          padding      : '5px 14px',
          borderRadius : '20px',
          fontSize     : '12px',
        }}>
          вљ  Only scan websites you own. Passive analysis only.
        </span>
      </header>

      {/* в”Ђв”Ђ Tab Navigation в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */}
      <nav style={{ padding: '20px 32px 0', display: 'flex', gap: '8px' }}>
        {tabs.map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab.toLowerCase())}
            style={{
              padding      : '8px 20px',
              background   : activeTab === tab.toLowerCase() ? '#fff' : 'transparent',
              color        : activeTab === tab.toLowerCase() ? '#000' : '#666',
              border       : '1px solid #222',
              borderRadius : '8px',
              cursor       : 'pointer',
              fontSize     : '14px',
              fontWeight   : '500',
              transition   : 'all 0.15s ease',
            }}
          >
            {tab}
          </button>
        ))}
      </nav>

      {/* в”Ђв”Ђ Page Content в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */}
      <main style={{ padding: '30px 32px' }}>

        {/* Scanner Tab */}
        {activeTab === 'scanner' && (
          <ScanPage
            onResult={(r) => {
              setResult(r);
              setActiveTab('report');
            }}
          />
        )}

        {/* Report Tab */}
        {activeTab === 'report' && (
          result
            ? <ResultPage result={result} />
            : <EmptyState message="Run a scan first to see the report." />
        )}

        {/* History Tab */}
        {activeTab === 'history' && (
          <HistoryTab history={history} onRefresh={fetchHistory} />
        )}

      </main>
    </div>
  );
}


/* в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
   History Tab
   Shows all past scans from the database
в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */
function HistoryTab({ history, onRefresh }) {

  const gradeColor = (g) => {
    if (!g) return '#fff';
    if (g.startsWith('A')) return '#00ff88';
    if (g.startsWith('B')) return '#4488ff';
    if (g.startsWith('C')) return '#ffaa00';
    return '#ff4444';
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto' }}>

      {/* Header row */}
      <div style={{
        display        : 'flex',
        justifyContent : 'space-between',
        alignItems     : 'center',
        marginBottom   : '20px',
      }}>
        <h2 style={{ color: '#fff', fontSize: '18px', fontWeight: '600' }}>
          Scan History
        </h2>
        <button
          onClick={onRefresh}
          style={{
            padding      : '6px 16px',
            background   : 'transparent',
            border       : '1px solid #333',
            borderRadius : '6px',
            color        : '#888',
            cursor       : 'pointer',
            fontSize     : '12px',
          }}
        >
          в†» Refresh
        </button>
      </div>

      {/* Empty state */}
      {history.length === 0 && (
        <EmptyState message="No scans yet. Run your first scan!" />
      )}

      {/* Scan rows */}
      {history.map((scan, i) => (
        <div
          key={i}
          style={{
            background     : '#111',
            border         : '1px solid #1e1e1e',
            borderRadius   : '10px',
            padding        : '14px 18px',
            marginBottom   : '10px',
            display        : 'flex',
            alignItems     : 'center',
            justifyContent : 'space-between',
            transition     : 'border-color 0.15s',
          }}
        >
          {/* URL + timestamp */}
          <div>
            <div style={{
              fontSize     : '14px',
              fontWeight   : '500',
              color        : '#fff',
              fontFamily   : 'monospace',
              marginBottom : '4px',
            }}>
              {scan.url}
            </div>
            <div style={{ fontSize: '11px', color: '#444' }}>
              {new Date(scan.created_at).toLocaleString()}
            </div>
          </div>

          {/* Grade + Score badge */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <span style={{
              fontSize   : '20px',
              fontWeight : '700',
              color      : gradeColor(scan.grade),
              fontFamily : 'monospace',
            }}>
              {scan.grade}
            </span>
            <span style={{
              fontSize     : '13px',
              color        : '#555',
              background   : '#1a1a1a',
              padding      : '3px 10px',
              borderRadius : '20px',
            }}>
              {scan.score}/100
            </span>
          </div>
        </div>
      ))}
    </div>
  );
}


/* в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
   Empty State вЂ” reusable placeholder
в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */
function EmptyState({ message }) {
  return (
    <p style={{
      color      : '#444',
      textAlign  : 'center',
      marginTop  : '60px',
      fontSize   : '14px',
    }}>
      {message}
    </p>
  );
}


export default App;
